+            });
+
+            var worker = new ClusterWorker(id, child);
+            _clusterWorkers[id] = worker;
+
+            child.on('exit', function(code, signal) {
+                worker.state = 'dead';
+                worker.emit('exit', code, signal);
+                self.emit('exit', worker, code, signal);
+                delete _clusterWorkers[id];
+            });
+
